// Cotacoes de mercado - Neo Vertex
// Criptos via CoinGecko (US$), NVIDIA via Finnhub (convertida p/ R$), cambio via AwesomeAPI.
// >>> Cole sua chave gratuita da Finnhub abaixo (finnhub.io/register).
//     Sem ela, as criptos funcionam normalmente e a NVIDIA fica indisponivel.
const FINNHUB_KEY = 'SUA_CHAVE_FINNHUB';

const cgIds = 'bitcoin,ethereum,tether,solana,sui,bittensor';
const cg = await this.helpers.httpRequest({ url: 'https://api.coingecko.com/api/v3/simple/price?ids=' + cgIds + '&vs_currencies=usd&include_24hr_change=true', json: true });
const fx = await this.helpers.httpRequest({ url: 'https://economia.awesomeapi.com.br/last/USD-BRL', json: true });
const cambio = (fx && fx.USDBRL && Number(fx.USDBRL.bid)) || null;

const nomes = { bitcoin: 'Bitcoin (BTC)', ethereum: 'Ethereum (ETH)', tether: 'Tether (USDT)', solana: 'Solana (SOL)', sui: 'Sui (SUI)', bittensor: 'Bittensor (TAO)' };
const linhas = Object.keys(nomes).map(function (id) {
  const d = cg[id];
  if (!d) return nomes[id] + ': sem dado agora';
  const v = Number(d.usd_24h_change || 0);
  return nomes[id] + ': US$ ' + Number(d.usd).toFixed(2) + ' (' + (v >= 0 ? '+' : '') + v.toFixed(2) + '% em 24h)';
});

let nvda = 'NVIDIA (NVDA): chave Finnhub nao configurada';
if (FINNHUB_KEY && FINNHUB_KEY !== 'SUA_CHAVE_FINNHUB') {
  try {
    const q = await this.helpers.httpRequest({ url: 'https://finnhub.io/api/v1/quote?symbol=NVDA&token=' + FINNHUB_KEY, json: true });
    if (q && q.c && cambio) {
      const v = Number(q.dp || 0);
      nvda = 'NVIDIA (NVDA): R$ ' + (q.c * cambio).toFixed(2) + ' (US$ ' + Number(q.c).toFixed(2) + ', ' + (v >= 0 ? '+' : '') + v.toFixed(2) + '% no dia)';
    } else {
      nvda = 'NVIDIA (NVDA): sem dado agora';
    }
  } catch (e) { nvda = 'NVIDIA (NVDA): sem dado agora'; }
}

const texto = ['Cotacoes de mercado agora:']
  .concat(linhas)
  .concat([
    nvda,
    'SpaceX: sem cotacao publica (empresa privada, fora da bolsa)',
    cambio ? ('Cambio US$ para R$: ' + cambio.toFixed(2)) : 'Cambio US$ para R$: indisponivel'
  ])
  .join('\n');

return [{ json: { resposta_mercado: texto } }];
